class Solution {
    public int nextBeautifulNumber(int n) {
        n++;
        while (!isBeautiful(n)) {
            n++;
        }
        return n;
    }

    private boolean isBeautiful(int num) {
        String str = String.valueOf(num);
        int[] count = new int[10];
        for (char c : str.toCharArray()) {
            count[c - '0']++;
        }
        for (char c : str.toCharArray()) {
            if (count[c - '0'] != c - '0') {
                return false;
            }
        }
        return true;
    }
}
